1541   /// The APInt version of std::countl_zero.
1542   ///
1543   /// It counts the number of zeros from the most significant bit to the first
1544   /// one bit.
1545   ///
1546   /// \returns BitWidth if the value is zero, otherwise returns the number of
1547   ///   zeros from the most significant bit to the first one bits.
1548   unsigned countl_zero() const {
1549     if (isSingleWord()) {
1550       unsigned unusedBits = APINT_BITS_PER_WORD - BitWidth;
1551       return llvm::countl_zero(U.VAL) - unusedBits;
1552     }
1553     return countLeadingZerosSlowCase();
1554   }
1555 
1556   unsigned countLeadingZeros() const { return countl_zero(); }
1557 
1558   /// Count the number of leading one bits.
1559   ///
1560   /// This function is an APInt version of std::countl_one. It counts the number
1561   /// of ones from the most significant bit to the first zero bit.
1562   ///
1563   /// \returns 0 if the high order bit is not set, otherwise returns the number
1564   /// of 1 bits from the most significant to the least
1565   unsigned countl_one() const {
1566     if (isSingleWord()) {
1567       if (LLVM_UNLIKELY(BitWidth == 0))
1568         return 0;
1569       return llvm::countl_one(U.VAL << (APINT_BITS_PER_WORD - BitWidth));
1570     }
1571     return countLeadingOnesSlowCase();
1572   }
1573 
1574   unsigned countLeadingOnes() const { return countl_one(); }
1575 
1576   /// Computes the number of leading bits of this APInt that are equal to its
1577   /// sign bit.
1578   unsigned getNumSignBits() const {
1579     return isNegative() ? countl_one() : countl_zero();
1580   }
