1582   /// Count the number of trailing zero bits.
1583   ///
1584   /// This function is an APInt version of std::countr_zero. It counts the
1585   /// number of zeros from the least significant bit to the first set bit.
1586   ///
1587   /// \returns BitWidth if the value is zero, otherwise returns the number of
1588   /// zeros from the least significant bit to the first one bit.
1589   unsigned countr_zero() const {
1590     if (isSingleWord()) {
1591       unsigned TrailingZeros = llvm::countr_zero(U.VAL);
1592       return (TrailingZeros > BitWidth ? BitWidth : TrailingZeros);
1593     }
1594     return countTrailingZerosSlowCase();
1595   }
1596 
1597   unsigned countTrailingZeros() const { return countr_zero(); }
1598 
1599   /// Count the number of trailing one bits.
1600   ///
1601   /// This function is an APInt version of std::countr_one. It counts the number
1602   /// of ones from the least significant bit to the first zero bit.
1603   ///
1604   /// \returns BitWidth if the value is all ones, otherwise returns the number
1605   /// of ones from the least significant bit to the first zero bit.
1606   unsigned countr_one() const {
1607     if (isSingleWord())
1608       return llvm::countr_one(U.VAL);
1609     return countTrailingOnesSlowCase();
1610   }
1611 
1612   unsigned countTrailingOnes() const { return countr_one(); }
